package com.nutrisense.mapper.auth; import com.nutrisense.dto.auth.*; import com.nutrisense.entity.User; import org.mapstruct.*; @Mapper(componentModel="spring", unmappedTargetPolicy=ReportingPolicy.IGNORE) public interface AuthMapper { @Mapping(target="id",ignore=true) @Mapping(target="passwordHash",ignore=true) @Mapping(target="accountStatus",ignore=true) @Mapping(target="emailVerified",ignore=true) @Mapping(target="phoneVerified",ignore=true) @Mapping(target="deleted",ignore=true) @Mapping(target="lastLogin",ignore=true) @Mapping(target="createdAt",ignore=true) @Mapping(target="updatedAt",ignore=true) User toEntity(RegisterRequest request); }
